445→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
446→  LET $query = string::lowercase(string::trim($q));
447→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
448→
449→  LET $task_rows = SELECT
450→    id,
451→    "task" AS kind,
452→    title AS text,
453→    extraction_confidence AS confidence,
454→    source_message AS sourceMessage,
455→    priority,
456→    created_at
457→  FROM task
458→  WHERE workspace = $workspace
459→    AND extraction_confidence != NONE
460→    AND string::contains(string::lowercase(title), $query)
461→  ORDER BY created_at DESC
462→  LIMIT $safe_limit;
463→
464→  LET $decision_rows = SELECT
465→    id,
466→    "decision" AS kind,
467→    summary AS text,
468→    extraction_confidence AS confidence,
469→    source_message AS sourceMessage,
470→    priority,
471→    created_at
472→  FROM decision
473→  WHERE workspace = $workspace
474→    AND extraction_confidence != NONE
475→    AND string::contains(string::lowercase(summary), $query)
476→  ORDER BY created_at DESC
477→  LIMIT $safe_limit;
478→
479→  LET $question_rows = SELECT
480→    id,
481→    "question" AS kind,
482→    text AS text,
483→    extraction_confidence AS confidence,
484→    source_message AS sourceMessage,
485→    priority,
486→    created_at
487→  FROM question
488→  WHERE workspace = $workspace
489→    AND extraction_confidence != NONE
490→    AND string::contains(string::lowercase(text), $query)
491→  ORDER BY created_at DESC
492→  LIMIT $safe_limit;
493→
494→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
495→};
496→
497→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
498→  LET $query = string::lowercase(string::trim($q));
499→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
500→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
501→
502→  LET $task_rows = SELECT
503→    id,
504→    "task" AS kind,
505→    title AS text,
506→    extraction_confidence AS confidence,
507→    source_message AS sourceMessage,
508→    priority,
509→    created_at
510→  FROM task
511→  WHERE workspace = $workspace
512→    AND extraction_confidence != NONE
513→    AND id IN $project_entity_ids
514→    AND string::contains(string::lowercase(title), $query)
515→  ORDER BY created_at DESC
516→  LIMIT $safe_limit;
517→
518→  LET $decision_rows = SELECT
519→    id,
520→    "decision" AS kind,
521→    summary AS text,
522→    extraction_confidence AS confidence,
523→    source_message AS sourceMessage,
524→    priority,
525→    created_at
526→  FROM decision
527→  WHERE workspace = $workspace
528→    AND extraction_confidence != NONE
529→    AND id IN $project_entity_ids
530→    AND string::contains(string::lowercase(summary), $query)
531→  ORDER BY created_at DESC
532→  LIMIT $safe_limit;
533→
534→  LET $question_rows = SELECT
535→    id,
536→    "question" AS kind,
537→    text AS text,
538→    extraction_confidence AS confidence,
539→    source_message AS sourceMessage,
540→    priority,
541→    created_at
542→  FROM question
543→  WHERE workspace = $workspace
544→    AND extraction_confidence != NONE
545→    AND id IN $project_entity_ids
546→    AND string::contains(string::lowercase(text), $query)
547→  ORDER BY created_at DESC
548→  LIMIT $safe_limit;
549→
550→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
551→};
