553→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
554→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
555→  RETURN SELECT id, role, text, createdAt
556→  FROM message
557→  WHERE conversation = $conversation
558→  ORDER BY createdAt DESC
559→  LIMIT $safe_limit;
560→};
