562→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
563→  RETURN SELECT
564→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
565→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
566→  FROM $entity;
567→};
