159→/**
160→ * Replace entity name mentions in response text with markdown links:
161→ *   "Model for Extraction Pipeline" → "[Model for Extraction Pipeline](entity://decision:uuid)"
162→ *
163→ * Matches longest names first to avoid partial replacement.
164→ * Only replaces the first occurrence of each entity name.
165→ */
166→function injectEntityLinks(text: string, context: ChatContext): string {
167→  const entities: KnownEntity[] = [];
168→
169→  for (const project of context.workspaceSummary.projects) {
170→    entities.push({ entityId: `project:${project.id}`, kind: "project", name: project.name });
171→  }
172→  for (const decision of context.workspaceSummary.recentDecisions) {
173→    entities.push({ entityId: `decision:${decision.id}`, kind: "decision", name: decision.name });
174→  }
175→  for (const question of context.workspaceSummary.openQuestions) {
176→    entities.push({ entityId: `question:${question.id}`, kind: "question", name: question.name });
177→  }
178→
179→  // Sort longest name first so "Agent-Native Business OS" matches before "Agent"
180→  entities.sort((a, b) => b.name.length - a.name.length);
181→
182→  const replaced = new Set<string>();
183→  let result = text;
184→
185→  for (const entity of entities) {
186→    if (entity.name.length < 3) continue;
187→    if (replaced.has(entity.entityId)) continue;
188→
189→    // Case-insensitive match, but only replace the first occurrence.
190→    // Skip if the name is already inside a markdown link.
191→    const idx = result.toLowerCase().indexOf(entity.name.toLowerCase());
192→    if (idx === -1) continue;
193→
194→    // Check if already inside a markdown link: [...](...)
195→    const before = result.slice(0, idx);
196→    if (before.lastIndexOf("[") > before.lastIndexOf("]")) continue;
197→
198→    const matched = result.slice(idx, idx + entity.name.length);
199→    const link = `[${matched}](#entity/${entity.entityId})`;
200→    result = `${result.slice(0, idx)}${link}${result.slice(idx + entity.name.length)}`;
201→    replaced.add(entity.entityId);
202→  }
203→
204→  return result;
205→}
