// Find the last DEFINE TABLE block and any DEFINE FUNCTION blocks
const lines = FILE_CONTENT.split('\n');
const totalLines = lines.length;
let lastDefineTable = -1;
let firstDefineFunction = -1;
let tableNames = [];

for (let i = 0; i < lines.length; i++) {
  if (lines[i].match(/^DEFINE TABLE/)) {
    lastDefineTable = i + 1;
    const match = lines[i].match(/^DEFINE TABLE (\w+)/);
    if (match) tableNames.push(`${i+1}: ${match[1]}`);
  }
  if (lines[i].match(/^DEFINE FUNCTION/) && firstDefineFunction === -1) {
    firstDefineFunction = i + 1;
  }
}

console.log(`Total lines: ${totalLines}`);
console.log(`Last DEFINE TABLE at line: ${lastDefineTable}`);
console.log(`First DEFINE FUNCTION at line: ${firstDefineFunction}`);
console.log('\nAll tables:');
tableNames.forEach(t => console.log(`  ${t}`));

// Show last 5 lines before first DEFINE FUNCTION
if (firstDefineFunction > 0) {
  console.log(`\nLines ${firstDefineFunction-5} to ${firstDefineFunction+2}:`);
  for (let i = firstDefineFunction - 6; i < firstDefineFunction + 2; i++) {
    if (i >= 0 && i < lines.length) {
      console.log(`  ${i+1}: ${lines[i]}`);
    }
  }
}

