const { Surreal } = require('surrealdb');
const { readFileSync } = require('node:fs');
const { join } = require('node:path');
async function main() {
  const surreal = new Surreal();
  await surreal.connect('ws://127.0.0.1:8000/rpc');
  await surreal.signin({ username: 'root', password: 'root' });
  const ns = 'test_migration_' + Date.now();
  const db = 'test_' + Date.now();
  await surreal.query('DEFINE NAMESPACE ' + ns + ';');
  await surreal.use({ namespace: ns });
  await surreal.query('DEFINE DATABASE ' + db + ';');
  await surreal.use({ namespace: ns, database: db });
  // Apply base schema
  const schema = readFileSync(join(process.cwd(), 'schema', 'surreal-schema.surql'), 'utf8');
  try {
    await surreal.query(schema);
    console.log('Base schema applied OK');
  } catch(e) {
    console.log('Base schema error:', e.message);
  }
  // Apply migration
  const migration = readFileSync(join(process.cwd(), 'schema', 'migrations', '0011_authority_scope.surql'), 'utf8');
  try {
    await surreal.query(migration);
    console.log('Migration applied OK');
  } catch(e) {
    console.log('Migration error:', e.message);
  }
  // Check count
  try {
    const [rows] = await surreal.query('SELECT count() FROM authority_scope GROUP ALL;');
    console.log('Row count:', JSON.stringify(rows));
  } catch(e) {
    console.log('Count error:', e.message);
  }
  // Cleanup
  await surreal.query('REMOVE NAMESPACE ' + ns + ';');
  surreal.close();
}
main().catch(e => console.error(e));
