import { describe, expect, it } from "bun:test";
import { RecordId } from "surrealdb";
import { setupSmokeSuite } from "./smoke-test-kit";
import { checkAuthority } from "../../app/src/server/iam/authority";
import { resolveByEmail } from "../../app/src/server/iam/identity";
import { resolveWorkspacePerson } from "../../app/src/server/extraction/person";

const getRuntime = setupSmokeSuite("authority");

describe("checkAuthority", () => {
  it("returns correct permission for code_agent create_task (auto)", async () => {
    const { surreal } = getRuntime();
    const result = await checkAuthority({
      surreal,
      agentType: "code_agent",
      action: "create_task",
    });
    expect(result).toBe("auto");
  });

  it("returns correct permission for code_agent confirm_decision (blocked)", async () => {
    const { surreal } = getRuntime();
    const result = await checkAuthority({
      surreal,
      agentType: "code_agent",
      action: "confirm_decision",
    });
    expect(result).toBe("blocked");
  });

  it("returns correct permission for code_agent create_decision (provisional)", async () => {
    const { surreal } = getRuntime();
    const result = await checkAuthority({
      surreal,
      agentType: "code_agent",
      action: "create_decision",
    });
    expect(result).toBe("provisional");
  });

  it("returns correct permission for observer create_task (blocked)", async () => {
    const { surreal } = getRuntime();
    const result = await checkAuthority({
      surreal,
      agentType: "observer",
      action: "create_task",
    });
    expect(result).toBe("blocked");
  });

  it("returns correct permission for observer create_observation (auto)", async () => {
    const { surreal } = getRuntime();
    const result = await checkAuthority({
      surreal,
      agentType: "observer",
      action: "create_observation",
    });
    expect(result).toBe("auto");
  });

  it("returns correct permission for design_partner create_task (provisional)", async () => {
    const { surreal } = getRuntime();
    const result = await checkAuthority({
      surreal,
      agentType: "design_partner",
      action: "create_task",
    });
    expect(result).toBe("provisional");
  });

  it("returns blocked for unknown agent_type/action combo", async () => {
    const { surreal } = getRuntime();
    const result = await checkAuthority({
      surreal,
      agentType: "code_agent",
      // @ts-expect-error — testing unknown action fallback
      action: "nonexistent_action",
    });
    expect(result).toBe("blocked");
  });

  it("workspace-specific override takes precedence", async () => {
    const { surreal } = getRuntime();
    const workspaceRecord = new RecordId("workspace", "test-ws-override");

    // Create workspace
    await surreal.create(workspaceRecord).content({
      name: "test-override",
      created_at: new Date(),
      updated_at: new Date(),
      onboarding_complete: true,
      onboarding_turn_count: 0,
    });

    // Verify global default first
    const globalResult = await checkAuthority({
      surreal,
      agentType: "code_agent",
      action: "create_task",
    });
    expect(globalResult).toBe("auto");

    // Create workspace-specific override
    await surreal.query(
      `CREATE authority_scope CONTENT {
        agent_type: "code_agent",
        action: "create_task",
        permission: "blocked",
        workspace: $workspace,
        created_at: time::now()
      };`,
      { workspace: workspaceRecord },
    );

    // Workspace-specific should override global
    const wsResult = await checkAuthority({
      surreal,
      agentType: "code_agent",
      action: "create_task",
      workspaceRecord,
    });
    expect(wsResult).toBe("blocked");

    // Without workspace, should still return global default
    const stillGlobal = await checkAuthority({
      surreal,
      agentType: "code_agent",
      action: "create_task",
    });
    expect(stillGlobal).toBe("auto");
  });
});

describe("identity resolution", () => {
  it("resolveByEmail finds person by case-insensitive email", async () => {
    const { surreal } = getRuntime();
    const workspaceRecord = new RecordId("workspace", "test-ws-identity");
    const personRecord = new RecordId("person", "test-person-email");

    await surreal.create(workspaceRecord).content({
      name: "test-identity",
      created_at: new Date(),
      updated_at: new Date(),
      onboarding_complete: true,
      onboarding_turn_count: 0,
    });

    await surreal.create(personRecord).content({
      name: "Test User",
      contact_email: "Test@Example.com",
      email_verified: false,
      created_at: new Date(),
      updated_at: new Date(),
    });

    await surreal
      .relate(personRecord, new RecordId("member_of", "test-membership"), workspaceRecord, {
        role: "member",
        added_at: new Date(),
      })
      .output("after");

    const result = await resolveByEmail({
      surreal,
      email: "test@example.com",
      workspaceRecord,
    });

    expect(result).toBeDefined();
    expect(result!.id).toBe("test-person-email");
  });

  it("resolveByEmail returns undefined for non-member", async () => {
    const { surreal } = getRuntime();
    const workspaceRecord = new RecordId("workspace", "test-ws-nonmember");
    const personRecord = new RecordId("person", "test-person-nonmember");

    await surreal.create(workspaceRecord).content({
      name: "test-nonmember",
      created_at: new Date(),
      updated_at: new Date(),
      onboarding_complete: true,
      onboarding_turn_count: 0,
    });

    await surreal.create(personRecord).content({
      name: "Outsider",
      contact_email: "outsider@example.com",
      email_verified: false,
      created_at: new Date(),
      updated_at: new Date(),
    });

    // No member_of edge — person is NOT in workspace
    const result = await resolveByEmail({
      surreal,
      email: "outsider@example.com",
      workspaceRecord,
    });

    expect(result).toBeUndefined();
  });

  it("resolveWorkspacePerson chains name match then email fallback", async () => {
    const { surreal } = getRuntime();
    const workspaceRecord = new RecordId("workspace", "test-ws-composite");
    const personRecord = new RecordId("person", "test-person-composite");

    await surreal.create(workspaceRecord).content({
      name: "test-composite",
      created_at: new Date(),
      updated_at: new Date(),
      onboarding_complete: true,
      onboarding_turn_count: 0,
    });

    await surreal.create(personRecord).content({
      name: "Alice",
      contact_email: "alice@example.com",
      email_verified: false,
      created_at: new Date(),
      updated_at: new Date(),
    });

    await surreal
      .relate(personRecord, new RecordId("member_of", "test-composite-member"), workspaceRecord, {
        role: "member",
        added_at: new Date(),
      })
      .output("after");

    // Name match
    const byName = await resolveWorkspacePerson({
      surreal,
      workspaceRecord,
      personName: "Alice",
    });
    expect(byName).toBeDefined();
    expect(byName!.id).toBe("test-person-composite");

    // Email fallback
    const byEmail = await resolveWorkspacePerson({
      surreal,
      workspaceRecord,
      personName: "alice@example.com",
    });
    expect(byEmail).toBeDefined();
    expect(byEmail!.id).toBe("test-person-composite");

    // No match
    const noMatch = await resolveWorkspacePerson({
      surreal,
      workspaceRecord,
      personName: "nobody",
    });
    expect(noMatch).toBeUndefined();
  });
});

